import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './TheaterBooking.css';

const TheaterBooking = () => {
    const [seats, setSeats] = useState([]);
    const [selectedSeats, setSelectedSeats] = useState([]);
    const [customerName, setCustomerName] = useState('');
    const [studentId, setStudentId] = useState('');
    const [faculty, setFaculty] = useState('');

    const faculties = [
        "Arhitektonski fakultet",
        "Biološki fakultet",
        "Ekonomski fakultet",
        "Elektrotehnički fakultet",
        "Fakultet bezbednosti",
        "Fakultet organizacionih nauka",
        "Fakultet političkih nauka",
        "Fakultet sporta i fizičkog vaspitanja",
        "Fakultet za fizičku hemiju",
        "Fakultet za specijalnu edukaciju i rehabilitaciju",
        "Farmaceutski fakultet",
        "Filološki fakultet",
        "Filozofski fakultet",
        "Fizički fakultet",
        "Građevinski fakultet",
        "Hemijski fakultet",
        "Mašinski fakultet",
        "Matematički fakultet",
        "Medicinski fakultet",
        "Pravni fakultet",
        "Pravoslavni bogoslovski fakultet",
        "Rudarsko-geološki fakultet",
        "Saobraćajni fakultet",
        "Stomatološki fakultet",
        "Šumarski fakultet",
        "Tehnički fakultet u Boru",
        "Tehnološko-metalurški fakultet",
        "Učiteljski fakultet",
        "Veterinarski fakultet"
    ];

    useEffect(() => {
        const initialSeats = [];
        const sections = ['A', 'B', 'C', 'D'];
        const rows = ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J'];
        let id = 1;
        
        sections.forEach(section => {
            rows.forEach(row => {
                for (let column = 1; column <= 16; column++) {
                    initialSeats.push({
                        id: id++,
                        section: section,
                        row: row,
                        column: column,
                        booked: false
                    });
                }
            });
        });
        
        setSeats(initialSeats);
    }, []);

    const fetchSeats = async () => {
        try {
            const response = await axios.get('http://localhost:8080/api/theater/seats');
            setSeats(response.data);
        } catch (error) {
            console.error('Error fetching seats:', error);
        }
    };

    const handleSeatClick = (seat) => {
        if (seat.booked) return;
        
        if (selectedSeats.find(s => s.id === seat.id)) {
            setSelectedSeats(selectedSeats.filter(s => s.id !== seat.id));
        } else {
            setSelectedSeats([...selectedSeats, seat]);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        
        const reservation = {
            customerName,
            studentId,
            faculty,
            seats: selectedSeats
        };

        try {
            await axios.post('http://localhost:8080/api/theater/reserve', reservation);
            alert('Rezervacija uspešna!');
            fetchSeats();
            setSelectedSeats([]);
            setCustomerName('');
            setStudentId('');
            setFaculty('');
        } catch (error) {
            console.error('Error making reservation:', error);
            alert('Rezervacija nije uspela. Molimo pokušajte ponovo.');
        }
    };

    const renderSection = (sectionId) => {
        return (
            <div className="section" key={sectionId}>
                <h3 className="section-title">Section {sectionId}</h3>
                
                {['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J'].map(row => (
                    <div key={`${sectionId}-${row}`} className="seat-row">
                        <div className="row-label">{row}</div>
                        {seats
                            .filter(seat => seat.section === sectionId && seat.row === row)
                            .sort((a, b) => a.column - b.column)
                            .map(seat => (
                                <div
                                    key={seat.id}
                                    className={`seat ${seat.booked ? 'booked' : ''} 
                                        ${selectedSeats.find(s => s.id === seat.id) ? 'selected' : ''}`}
                                    onClick={() => handleSeatClick(seat)}
                                    title={`Section ${seat.section}, Row ${seat.row}, Seat ${seat.column}`}
                                >
                                    {seat.column}
                                </div>
                            ))}
                    </div>
                ))}
            </div>
        );
    };

    return (
        <div className="theater-booking">
            <div className="screen">SCREEN</div>
            
            <div className="seating-plan">
                <div className="sections-container">
                    {['A', 'B', 'C', 'D'].map(section => renderSection(section))}
                </div>
            </div>

            <div className="legend">
                <div className="legend-item">
                    <div className="seat"></div>
                    <span>Available</span>
                </div>
                <div className="legend-item">
                    <div className="seat selected"></div>
                    <span>Selected</span>
                </div>
                <div className="legend-item">
                    <div className="seat booked"></div>
                    <span>Booked</span>
                </div>
            </div>

            {selectedSeats.length > 0 && (
                <form className="booking-form" onSubmit={handleSubmit}>
                    <h3>Završite Vašu Rezervaciju</h3>
                    <p>Izabrana sedišta: {selectedSeats.map(seat => 
                        `Sekcija ${seat.section}, Red ${seat.row}, Sedište ${seat.column}`).join('; ')}
                    </p>
                    
                    <div className="form-group">
                        <label htmlFor="customerName">Ime i Prezime</label>
                        <input
                            id="customerName"
                            type="text"
                            placeholder="Unesite ime i prezime"
                            value={customerName}
                            onChange={(e) => setCustomerName(e.target.value)}
                            required
                        />
                    </div>
                    
                    <div className="form-group">
                        <label htmlFor="studentId">Broj Indeksa</label>
                        <input
                            id="studentId"
                            type="text"
                            placeholder="npr. 2023/0123"
                            value={studentId}
                            onChange={(e) => setStudentId(e.target.value)}
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="faculty">Fakultet</label>
                        <select
                            id="faculty"
                            value={faculty}
                            onChange={(e) => setFaculty(e.target.value)}
                            required
                            className="faculty-select"
                        >
                            <option value="">Izaberite fakultet</option>
                            {faculties.map((fac, index) => (
                                <option key={index} value={fac}>{fac}</option>
                            ))}
                        </select>
                    </div>
                    
                    <button type="submit">Rezervišite Mesta</button>
                </form>
            )}
        </div>
    );
};

export default TheaterBooking;
